const { useState, useMemo, Fragment } = React;

// Constants and utilities
const verticals = {
  Manufacturing: { questions: ["Should direct materials, MRO, and capex follow different approval patterns?", "Do receipts require inventory creation or quality inspection automation?", "Which plants or departments require distinct approval chains?"] },
  Healthcare: { questions: ["Which commodities require clinical, pharmacy, or patient-safety review?", "What urgent scenarios require accelerated routing?", "Which exceptions bypass standard routing?"] },
  "Higher Education": { questions: ["Do grants or restricted funds override department approval?", "Do principal investigators approve by grant, department, or amount?", "Are there fiscal year-end hold requirements?"] },
  "Public Sector": { questions: ["Which statutory thresholds require procurement intervention?", "Which categories require legal or policy review?", "How are overrides recorded for audit?"] },
  "Life Sciences": { questions: ["Which categories require QA or EHS review?", "Which controlled items require separate notification or approval?", "What evidence is required for exception approval?"] },
};

const questionBank = {
  foundations: ["Which workflow type is being designed: requisition, receipt, contract approval, invoice, or another process?", "What business objective is the workflow solving: budget control, policy compliance, category oversight, inventory handling, legal review, or segregation of duties?", "Which approval dimensions materially change routing: department, commodity, amount, GL account, project, supplier, or custom field?", "Which conditions should create separate steps versus only different approvers within the same step?"],
  governance: ["What are the approval thresholds by department, entity, or role?", "Which approvals expire, and is expiry driven by department, user, role, or specific GL accounts?", "Which exceptions bypass standard routing, and who is authorized to define or approve them?", "Are there mandatory reviewers for specific commodities or regulated categories?"],
  technical: ["Which rules can be maintained by the customer in ADW versus hard-coded in XML?", "Which folders already exist, and which shared folders or robots must be created?", "Are there automated steps such as Create PO, Compile File, Create Inventory, or notification activities?", "What test cases are needed for positive, negative, exception, and expiry scenarios?"],
};

const worksheetPresets = [
  { id: "p2o_validation", label: "P2O validation", matchers: ["p2o", "validation"], defaultMode: "static", hints: { approval: ["approval name", "approver"], ruleName: ["rule name", "mapping id"], commodity: ["commodity code", "category code"], company: ["company code"], amount: ["total amount", "pr amount"], amountDiff: ["amountdiff", "price increase"], department: ["department"], costCenter: ["cost center"], glAccount: ["gl account"], internalOrder: ["internal order"], wbs: ["wbs element"] } },
  { id: "order_change", label: "Order change", matchers: ["order", "change"], defaultMode: "static", hints: { approval: ["approval name", "approver"], ruleName: ["rule name"], commodity: ["category code"], company: ["company code"], amount: ["totalamount1", "total amount"], amountDiff: ["amountdiff1"], department: ["department"], costCenter: ["cost center"], glAccount: ["gl account"], internalOrder: ["internal order"], wbs: ["wbs element"] } },
  { id: "monetary", label: "Monetary", matchers: ["monetary"], defaultMode: "static", hints: { approval: ["approval name", "approver"], ruleName: ["rule name"], commodity: ["category code"], company: ["company code"], amount: ["pr amount", "total amount"], amountDiff: ["po price increase"], department: ["department"], costCenter: ["cost center"], glAccount: ["gl account"], internalOrder: ["internal order"], wbs: ["wbs element"] } },
];

const EMPTY_MAPPING = { approval: "", ruleName: "", commodity: "", company: "", amount: "", amountDiff: "", department: "", costCenter: "", glAccount: "", internalOrder: "", wbs: "" };

const BUILDER_DEFAULTS = {
  workflowType: "requisition", versionDescription: "Generated by Jaggaer Approval Workflow Studio V7", vertical: "Manufacturing", includeExpiration: true, expiryMode: "department", useInventoryRobot: false, sampleDepartment: "Operations", sampleCommodity: "Capex Equipment", sampleGl: "1505",
  approvals: [
    { id: 1, name: "Department Approval", mode: "dynamic", driver: "department", threshold: "0", folder: "" },
    { id: 2, name: "Commodity Specialist", mode: "adw", driver: "commodity", threshold: "0", folder: "" },
    { id: 3, name: "Capital Approval", mode: "adw", driver: "glAccount", threshold: "10000", folder: "" },
  ],
};

const QUESTIONNAIRE_DEFAULTS = { customerName: "", workflowType: "requisition", vertical: "Manufacturing", versionDescription: "Generated from customer questionnaire", routeByDepartment: true, routeByCommodity: true, routeByAmount: true, routeByGl: false, includeExpiry: true, expiryMode: "department", highValueThreshold: "25000", departmentFolder: "Department Approval", commodityFolder: "Commodity Review", glFolder: "Finance Approval", needsInventoryRobot: false, notes: "" };

const normalizeHeader = (v) => String(v || "").toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
const pickHeader = (headers, hints) => { const n = headers.map(h => ({ raw: h, norm: normalizeHeader(h) })); const f = n.find(i => hints.some(hint => i.norm.includes(hint))); return f ? f.raw : ""; };
const detectPreset = (name) => worksheetPresets.find(p => p.matchers.every(t => normalizeHeader(name).includes(t))) || worksheetPresets[0];
const detectMapping = (headers, preset) => { const p = preset || worksheetPresets[0]; const n = { ...EMPTY_MAPPING }; Object.keys(n).forEach(k => { n[k] = p.hints[k] ? pickHeader(headers, p.hints[k]) : ""; }); return n; };
const parseThreshold = (raw) => { const t = String(raw || "").trim(); if (!t) return ""; const k = t.match(/(\d+(?:\.\d+)?)\s*k/i); if (k) return String(Math.round(Number(k[1]) * 1000)); const c = t.match(/(?:>=|=>|>|=)\s*(\d+(?:\.\d+)?)/); if (c) return String(Number(c[1])); const a = t.match(/(\d+(?:\.\d+)?)/); return a ? String(Number(a[1])) : ""; };
const escapeXml = (v) => String(v ?? "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&apos;");
const slugify = (v) => String(v || "").replace(/[^A-Za-z0-9]+/g, " ").trim().split(/\s+/).map((p, i) => i === 0 ? p : p.charAt(0).toUpperCase() + p.slice(1)).join("") || "Activity";
const recommendMode = (s) => s.mode === "adw" ? "ADW" : s.mode === "dynamic" ? "Dynamic" : "Static";

const buildRuleFromForm = (form, step) => {
  const t = Number(step.threshold || 0);
  if (step.templateRule) return step.templateRule;
  if (step.mode === "adw") return `Document.RequiresRuleGroupEvaluation("${step.name}") == true`;
  if (step.mode === "dynamic" && step.driver === "department") return t > 0 ? `Document.RequiresDepartmentalApproval() == true && [Document.TotalAmount() >= ${t}]` : `Document.RequiresDepartmentalApproval() == true`;
  if (step.driver === "department") return t > 0 ? `[Document.CustomFieldValues("Department") in {"${form.sampleDepartment}"}] && [Document.TotalAmount() >= ${t}]` : `[Document.CustomFieldValues("Department") in {"${form.sampleDepartment}"}]`;
  if (step.driver === "commodity") return `[Document.CustomFieldValues("Commodity Code") in {"${form.sampleCommodity}"}]`;
  if (step.driver === "glAccount") return t > 0 ? `[Document.AccountCode() in {"${form.sampleGl}"}] && [Document.TotalAmount() >= ${t}]` : `[Document.AccountCode() in {"${form.sampleGl}"}]`;
  return `Document.TotalAmount() >= ${t || 1}`;
};

const buildWorkflowModel = (form) => {
  const steps = [], activities = [], relationships = [], folders = [];
  const addStep = (n, h) => { if (n && !steps.some(s => s.name === n)) steps.push({ name: n, help: h }); };
  const addFolder = (n, t) => { if (n && !folders.some(f => f.name === n)) folders.push({ name: n, type: t }); };
  activities.push({ name: "START", type: "start", folderSelectionRule: "Dummy", rule: "" });
  form.approvals.forEach(step => {
    const fsr = step.mode === "adw" ? "MultiElementDynamic" : step.mode === "dynamic" && step.driver === "department" ? "Department" : "ExplicitFolder";
    const fr = fsr === "ExplicitFolder" ? (step.folder || "") : "";
    const attrs = [];
    if (step.mode === "adw") attrs.push({ name: "RuleGroupInternalName", value: step.name });
    attrs.push({ name: "wfActivityHelp", value: step.templateRule ? "Spreadsheet-driven approval." : `${recommendMode(step)} approval driven by ${step.driver}.` });
    if (form.includeExpiration) attrs.push({ name: "wfActivitySupportNote", value: `Validate delegation and expiry handling by ${form.expiryMode}.` });
    activities.push({ name: slugify(step.name), type: "manual", stepName: step.name, folderRef: fr, folderSelectionRule: fsr, rule: buildRuleFromForm(form, step), attrs });
    addStep(step.name, `Workflow step for ${step.name}.`);
    if (fr) addFolder(fr, "shared");
  });
  if (["Healthcare", "Life Sciences"].includes(form.vertical)) {
    activities.push({ name: "SafetyNotification", type: "notification", folderRef: "Safety Notification", folderSelectionRule: "ExplicitFolder", rule: `[Product.HazMat = true || Product.Controlled = true]`, attrs: [{ name: "wfActivityHelp", value: "Notification for regulated items." }] });
    addFolder("Safety Notification", "shared");
  }
  if (form.workflowType === "receipt" && form.useInventoryRobot) {
    activities.push({ name: "CreateInventory", type: "automated", stepName: "Create Inventory Receipts", folderRef: "Create Inventory", folderSelectionRule: "ExplicitFolder", rule: "true", attrs: [{ name: "wfActivityHelp", value: "Automated inventory receipt creation." }] });
    addStep("Create Inventory Receipts", "System step to create inventory receipts.");
    addFolder("Create Inventory", "automated");
  }
  activities.push({ name: "END", type: "end", folderSelectionRule: "Dummy", rule: "" });
  for (let i = 0; i < activities.length - 1; i++) relationships.push({ previous: activities[i].name, next: activities[i + 1].name });
  return { steps, activities, relationships, folders };
};

const buildXmlFromForm = (form) => {
  const m = buildWorkflowModel(form);
  const sub = form.workflowType === "contract" ? "  <WorkflowSubType>Approval</WorkflowSubType>\n" : "";
  const stepsXml = m.steps.map(s => `  <Step name="${escapeXml(s.name)}">\n    <Attribute name="wfActivityHelp"><AttrValue lang="default">${escapeXml(s.help)}</AttrValue></Attribute>\n  </Step>`).join("\n");
  const activitiesXml = m.activities.map(a => {
    const sr = a.stepName ? `\n    <StepRef name="${escapeXml(a.stepName)}" />` : "";
    const fr = a.folderRef ? `\n    <FolderRef name="${escapeXml(a.folderRef)}" />` : "";
    const at = (a.attrs || []).map(attr => `\n    <Attribute name="${escapeXml(attr.name)}"><AttrValue lang="default">${escapeXml(attr.value)}</AttrValue></Attribute>`).join("");
    const r = a.rule ? `<![CDATA[${a.rule}]]>` : "";
    return `  <Activity name="${escapeXml(a.name)}">\n    <ActivityType>${escapeXml(a.type)}</ActivityType>${sr}${fr}\n    <Rule>${r}</Rule>\n    <FolderSelectionRule>${escapeXml(a.folderSelectionRule)}</FolderSelectionRule>${at}\n  </Activity>`;
  }).join("\n");
  const relsXml = m.relationships.map(r => `  <ActivityRelationship previous="${escapeXml(r.previous)}" next="${escapeXml(r.next)}" />`).join("\n");
  return `<?xml version="1.0" encoding="UTF-8"?>\n<!DOCTYPE ProcessDefinition SYSTEM "https://usertest.sciquest.com/app_docs/dtd/workflow/WorkflowDefinition.dtd">\n<ProcessDefinition>\n  <WorkflowType>${escapeXml(form.workflowType)}</WorkflowType>\n${sub}  <Usable>true</Usable>\n  <Version>1</Version>\n  <VersionDescription>${escapeXml(form.versionDescription)}</VersionDescription>\n  <!--====== Steps ======-->\n${stepsXml}\n  <!--====== Activities ======-->\n${activitiesXml}\n  <!--====== Activity relationships ======-->\n${relsXml}\n</ProcessDefinition>`;
};

const questionnaireToForm = (q) => {
  const approvals = [];
  if (q.routeByDepartment) approvals.push({ id: 1, name: "Department Approval", mode: "dynamic", driver: "department", threshold: "0", folder: q.departmentFolder || "" });
  if (q.routeByCommodity) approvals.push({ id: 2, name: "Commodity Review", mode: "static", driver: "commodity", threshold: "0", folder: q.commodityFolder || "Commodity Review" });
  if (q.routeByAmount) approvals.push({ id: 3, name: "High Value Approval", mode: "adw", driver: "amount", threshold: q.highValueThreshold || "25000", folder: "" });
  if (q.routeByGl) approvals.push({ id: 4, name: "GL Approval", mode: "static", driver: "glAccount", threshold: "0", folder: q.glFolder || "Finance Approval" });
  return { workflowType: q.workflowType, versionDescription: q.versionDescription || "Generated from questionnaire", vertical: q.vertical, includeExpiration: q.includeExpiry, expiryMode: q.expiryMode, useInventoryRobot: q.needsInventoryRobot, sampleDepartment: "Customer Department", sampleCommodity: "Customer Commodity", sampleGl: "Customer GL", approvals };
};

const validateXml = (xml) => {
  const issues = [];
  if (!xml.includes("<ProcessDefinition>")) issues.push("Missing <ProcessDefinition> root.");
  if (!xml.includes("<WorkflowType>")) issues.push("Missing <WorkflowType>.");
  if (!xml.includes('<Activity name="START">')) issues.push("Missing START activity.");
  if (!xml.includes('<Activity name="END">')) issues.push("Missing END activity.");
  if (!xml.includes("<ActivityRelationship")) issues.push("Missing activity relationships.");
  return issues;
};

const downloadText = (filename, text) => {
  const blob = new Blob([text], { type: "text/plain;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url; link.download = filename;
  document.body.appendChild(link); link.click();
  document.body.removeChild(link); URL.revokeObjectURL(url);
};

// Components
const Section = ({ title, subtitle, children }) => (
  <div className="rounded-3xl border border-slate-200 bg-white p-4 shadow-sm">
    <div className="mb-3">
      <div className="text-base font-semibold text-slate-900">{title}</div>
      {subtitle && <div className="mt-1 text-sm text-slate-500">{subtitle}</div>}
    </div>
    {children}
  </div>
);

const SmallTag = ({ children }) => <span className="rounded-full border border-slate-200 bg-slate-50 px-2 py-1 text-xs text-slate-700">{children}</span>;

const VisualWorkflowDashboard = ({ form, title, subtitle }) => {
  const model = useMemo(() => buildWorkflowModel(form), [form]);
  const nodes = model.activities.map(a => ({ id: a.name, label: a.stepName || a.name, kind: a.type }));
  const kindStyle = (k) => k === "start" || k === "end" ? "border-slate-300 bg-slate-50 text-slate-700" : k === "automated" ? "border-emerald-300 bg-emerald-50 text-emerald-800" : k === "notification" ? "border-amber-300 bg-amber-50 text-amber-800" : "border-sky-300 bg-sky-50 text-sky-800";
  return (
    <Section title={title} subtitle={subtitle}>
      <div className="rounded-2xl border-4 border-sky-600/60 bg-white p-4">
        <div className="mb-2 text-sm font-medium text-slate-700">Workflow process</div>
        <div className="overflow-x-auto pb-2">
          <div className="flex min-w-max items-center gap-3">
            {nodes.map((n, i) => (
              <Fragment key={n.id}>
                <div className={`min-w-[140px] rounded-2xl border px-3 py-2 text-center text-sm font-semibold shadow-sm ${kindStyle(n.kind)}`}>{n.label}</div>
                {i < nodes.length - 1 && <div className="h-0.5 w-8 bg-slate-300" />}
              </Fragment>
            ))}
          </div>
        </div>
      </div>
      <div className="mt-4 grid gap-4 lg:grid-cols-2">
        <div className="rounded-2xl border-4 border-sky-600/60 bg-white p-4">
          <div className="mb-2 text-sm font-semibold text-slate-900">Steps</div>
          <div className="space-y-2 text-sm">{model.steps.length === 0 ? <div>No steps defined.</div> : model.steps.map(s => <div key={s.name} className="rounded-xl border border-slate-200 bg-slate-50 p-2"><div className="font-semibold">{s.name}</div><div className="text-xs text-slate-600">{s.help}</div></div>)}</div>
        </div>
        <div className="rounded-2xl border-4 border-amber-500/70 bg-white p-4">
          <div className="mb-2 text-sm font-semibold text-slate-900">Activities</div>
          <div className="space-y-2 text-sm max-h-[300px] overflow-auto">{model.activities.map(a => <div key={a.name} className="rounded-xl border border-slate-200 bg-slate-50 p-2"><div className="font-semibold">{a.name}</div><div className="text-xs text-slate-600">{a.type}{a.stepName ? ` | ${a.stepName}` : ""}{a.folderRef ? ` | ${a.folderRef}` : ""}</div><div className="mt-1 rounded bg-white px-2 py-1 font-mono text-[10px] text-slate-600">{a.rule || "(no rule)"}</div></div>)}</div>
        </div>
      </div>
    </Section>
  );
};

const BuilderMode = ({ form, setForm, xmlDraft, setXmlDraft }) => {
  const model = useMemo(() => buildWorkflowModel(form), [form]);
  const blueprint = useMemo(() => {
    const l = [`Workflow Type: ${form.workflowType}`, `Vertical: ${form.vertical}`, `Strategy: ${form.approvals.map(a => `${a.name}=${recommendMode(a)}`).join(" | ")}`, "", "Folders"];
    if (!model.folders.length) l.push("- None required");
    model.folders.forEach(f => l.push(`- ${f.name} [${f.type}]`));
    l.push("", "Steps"); model.steps.forEach((s, i) => l.push(`${i + 1}. ${s.name}`));
    l.push("", "Activities"); model.activities.forEach(a => { l.push(`- ${a.name} | ${a.type} | ${a.folderSelectionRule}`); l.push(`  rule: ${a.rule || "(none)"}`); });
    l.push("", "Relationships"); model.relationships.forEach(r => l.push(`- ${r.previous} -> ${r.next}`));
    return l.join("\n");
  }, [form, model]);
  const issues = useMemo(() => validateXml(xmlDraft), [xmlDraft]);
  const updateApproval = (id, patch) => setForm(c => ({ ...c, approvals: c.approvals.map(i => i.id === id ? { ...i, ...patch } : i) }));
  return (
    <div className="grid gap-6 xl:grid-cols-2">
      <div className="space-y-6">
        <Section title="Builder: workflow structure" subtitle="Build folders, approvers, steps, and routing.">
          <div className="grid gap-3 md:grid-cols-2">
            <label className="text-sm"><div className="mb-1 font-medium">Workflow type</div><select value={form.workflowType} onChange={e => setForm(c => ({ ...c, workflowType: e.target.value }))} className="w-full rounded-2xl border border-slate-200 bg-white px-3 py-2"><option value="requisition">requisition</option><option value="receipt">receipt</option><option value="contract">contract</option></select></label>
            <label className="text-sm"><div className="mb-1 font-medium">Version description</div><input value={form.versionDescription} onChange={e => setForm(c => ({ ...c, versionDescription: e.target.value }))} className="w-full rounded-2xl border border-slate-200 px-3 py-2" /></label>
            <label className="text-sm"><div className="mb-1 font-medium">Sample department</div><input value={form.sampleDepartment} onChange={e => setForm(c => ({ ...c, sampleDepartment: e.target.value }))} className="w-full rounded-2xl border border-slate-200 px-3 py-2" /></label>
            <label className="text-sm"><div className="mb-1 font-medium">Sample commodity</div><input value={form.sampleCommodity} onChange={e => setForm(c => ({ ...c, sampleCommodity: e.target.value }))} className="w-full rounded-2xl border border-slate-200 px-3 py-2" /></label>
            <label className="text-sm"><div className="mb-1 font-medium">Sample GL</div><input value={form.sampleGl} onChange={e => setForm(c => ({ ...c, sampleGl: e.target.value }))} className="w-full rounded-2xl border border-slate-200 px-3 py-2" /></label>
            <label className="inline-flex items-center gap-2 rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm mt-6"><input type="checkbox" checked={form.useInventoryRobot} onChange={e => setForm(c => ({ ...c, useInventoryRobot: e.target.checked }))} /> Include inventory automation</label>
          </div>
          <div className="mt-4 space-y-4">
            {form.approvals.map(a => (
              <div key={a.id} className="rounded-2xl border border-slate-200 p-3">
                <div className="grid gap-2 md:grid-cols-5">
                  <label className="text-sm md:col-span-2"><div className="mb-1 font-medium">Step name</div><input value={a.name} onChange={e => updateApproval(a.id, { name: e.target.value })} className="w-full rounded-xl border border-slate-200 px-3 py-2" /></label>
                  <label className="text-sm"><div className="mb-1 font-medium">Mode</div><select value={a.mode} onChange={e => updateApproval(a.id, { mode: e.target.value })} className="w-full rounded-xl border border-slate-200 px-3 py-2"><option value="static">static</option><option value="dynamic">dynamic</option><option value="adw">adw</option></select></label>
                  <label className="text-sm"><div className="mb-1 font-medium">Driver</div><select value={a.driver} onChange={e => updateApproval(a.id, { driver: e.target.value })} className="w-full rounded-xl border border-slate-200 px-3 py-2"><option value="department">department</option><option value="commodity">commodity</option><option value="amount">amount</option><option value="glAccount">gl account</option></select></label>
                  <label className="text-sm"><div className="mb-1 font-medium">Threshold</div><input value={a.threshold} onChange={e => updateApproval(a.id, { threshold: e.target.value })} className="w-full rounded-xl border border-slate-200 px-3 py-2" /></label>
                </div>
                <div className="mt-2 grid gap-2 md:grid-cols-2">
                  <label className="text-sm"><div className="mb-1 font-medium">Folder</div><input value={a.folder} onChange={e => updateApproval(a.id, { folder: e.target.value })} disabled={a.mode === "adw"} className="w-full rounded-xl border border-slate-200 px-3 py-2 disabled:bg-slate-100" placeholder={a.mode === "adw" ? "Not used for ADW" : "Folder name"} /></label>
                  <label className="text-sm"><div className="mb-1 font-medium">Custom rule</div><input value={a.templateRule || ""} onChange={e => updateApproval(a.id, { templateRule: e.target.value })} className="w-full rounded-xl border border-slate-200 px-3 py-2" placeholder="Optional rule override" /></label>
                </div>
              </div>
            ))}
          </div>
          <div className="mt-4 flex flex-wrap gap-2">
            <button onClick={() => setForm(c => ({ ...c, approvals: [...c.approvals, { id: Date.now(), name: `Approval ${c.approvals.length + 1}`, mode: "adw", driver: "amount", threshold: "0", folder: "" }] }))} className="rounded-2xl bg-slate-900 px-4 py-2 text-sm font-medium text-white">Add step</button>
            <button onClick={() => setXmlDraft(buildXmlFromForm(form))} className="rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm font-medium text-slate-800">Generate XML</button>
          </div>
        </Section>
      </div>
      <div className="space-y-6">
        <VisualWorkflowDashboard form={form} title="Workflow dashboard" subtitle="Visualize workflow before export." />
        <Section title="Blueprint" subtitle="Folders, steps, activities, relationships."><pre className="max-h-[280px] overflow-auto rounded-2xl bg-slate-950 p-4 text-xs leading-5 text-emerald-300">{blueprint}</pre></Section>
        <Section title="XML Output" subtitle="Edit, validate, and export.">
          <textarea value={xmlDraft} onChange={e => setXmlDraft(e.target.value)} rows={14} className="w-full rounded-2xl border border-slate-200 bg-slate-950 px-3 py-3 font-mono text-xs leading-5 text-emerald-300" />
          <div className="mt-3 flex flex-wrap gap-2">
            <button onClick={() => downloadText(`${form.workflowType}-builder.xml`, xmlDraft)} className="rounded-2xl bg-slate-900 px-4 py-2 text-sm font-medium text-white">Export XML</button>
            <button onClick={() => downloadText(`${form.workflowType}-blueprint.txt`, blueprint)} className="rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm font-medium text-slate-800">Export blueprint</button>
          </div>
          <div className="mt-3">{issues.length === 0 ? <div className="rounded-2xl border border-emerald-200 bg-emerald-50 p-3 text-sm text-emerald-800">No issues detected.</div> : issues.map(i => <div key={i} className="rounded-2xl border border-amber-200 bg-amber-50 p-3 text-sm text-amber-900 mb-2">{i}</div>)}</div>
        </Section>
      </div>
    </div>
  );
};

const TemplateMode = ({ form, setForm, templateXml, setTemplateXml }) => {
  const [workbookName, setWorkbookName] = useState("");
  const [sheets, setSheets] = useState({});
  const [sheetNames, setSheetNames] = useState([]);
  const [selectedSheet, setSelectedSheet] = useState("");
  const [sheetRows, setSheetRows] = useState([]);
  const [presetId, setPresetId] = useState(worksheetPresets[0].id);
  const [mapping, setMapping] = useState({ ...EMPTY_MAPPING });
  const headers = useMemo(() => sheetRows.length ? Object.keys(sheetRows[0]) : [], [sheetRows]);
  const activePreset = useMemo(() => worksheetPresets.find(p => p.id === presetId) || worksheetPresets[0], [presetId]);
  const issues = useMemo(() => validateXml(templateXml), [templateXml]);

  const applyRows = (name, s, pid) => {
    const rows = s[name] || [];
    const preset = pid ? worksheetPresets.find(p => p.id === pid) || worksheetPresets[0] : detectPreset(name);
    setSelectedSheet(name); setSheetRows(rows); setPresetId(preset.id);
    setMapping(rows.length ? detectMapping(Object.keys(rows[0]), preset) : { ...EMPTY_MAPPING });
  };

  const uploadWorkbook = async (e) => {
    const file = e.target.files?.[0]; if (!file) return;
    const buffer = await file.arrayBuffer();
    const wb = XLSX.read(buffer, { type: "array" });
    const ns = {};
    wb.SheetNames.forEach(n => { ns[n] = XLSX.utils.sheet_to_json(wb.Sheets[n], { defval: "" }); });
    setWorkbookName(file.name); setSheets(ns); setSheetNames(wb.SheetNames);
    if (wb.SheetNames[0]) applyRows(wb.SheetNames[0], ns, "");
  };

  const buildFromSheet = () => {
    if (!sheetRows.length || !mapping.approval) return;
    const groups = new Map();
    sheetRows.forEach((row, i) => {
      const approver = String(row[mapping.approval] || "").trim() || `Approver ${i + 1}`;
      if (!groups.has(approver)) groups.set(approver, []);
      groups.get(approver).push(row);
    });
    const approvals = Array.from(groups.entries()).slice(0, 20).map(([approver, rows], i) => ({
      id: Date.now() + i, name: approver.slice(0, 80), mode: activePreset.defaultMode || "static",
      driver: mapping.commodity && rows[0][mapping.commodity] ? "commodity" : mapping.department && rows[0][mapping.department] ? "department" : "amount",
      threshold: parseThreshold(mapping.amount ? rows[0][mapping.amount] : "") || "0", folder: approver.slice(0, 80),
      templateRule: rows.map(r => { const parts = []; if (mapping.commodity && r[mapping.commodity]) parts.push(`[Document.CustomFieldValues("Commodity Code") in {"${r[mapping.commodity]}"}]`); if (mapping.department && r[mapping.department]) parts.push(`[Document.CustomFieldValues("Department") in {"${r[mapping.department]}"}]`); if (mapping.glAccount && r[mapping.glAccount]) parts.push(`[Document.AccountCode() in {"${r[mapping.glAccount]}"}]`); const t = parseThreshold(mapping.amount ? r[mapping.amount] : ""); if (t) parts.push(`[Document.TotalAmount() >= ${t}]`); return parts.length ? `(${parts.join(" && ")})` : "true"; }).join(" || ") || "true"
    }));
    const nextForm = { ...form, approvals };
    setForm(nextForm); setTemplateXml(buildXmlFromForm(nextForm));
  };

  return (
    <div className="grid gap-6 xl:grid-cols-2">
      <div className="space-y-6">
        <Section title="Template import" subtitle="Upload customer spreadsheet to generate workflow.">
          <div className="grid gap-3 md:grid-cols-2">
            <label className="text-sm"><div className="mb-1 font-medium">Upload template</div><input type="file" accept=".xlsx,.xls" onChange={uploadWorkbook} className="w-full rounded-2xl border border-slate-200 bg-white px-3 py-2 text-sm" /></label>
            <div className="rounded-2xl bg-slate-50 p-3 text-sm"><div className="font-medium">Loaded workbook</div><div className="mt-1">{workbookName || "No workbook loaded"}</div></div>
          </div>
          <div className="mt-4 grid gap-3 md:grid-cols-3">
            <label className="text-sm"><div className="mb-1 font-medium">Worksheet</div><select value={selectedSheet} onChange={e => applyRows(e.target.value, sheets, presetId)} className="w-full rounded-2xl border border-slate-200 bg-white px-3 py-2"><option value="">Select sheet</option>{sheetNames.map(n => <option key={n} value={n}>{n}</option>)}</select></label>
            <label className="text-sm"><div className="mb-1 font-medium">Preset</div><select value={presetId} onChange={e => { setPresetId(e.target.value); setMapping(detectMapping(headers, worksheetPresets.find(p => p.id === e.target.value))); }} className="w-full rounded-2xl border border-slate-200 bg-white px-3 py-2">{worksheetPresets.map(p => <option key={p.id} value={p.id}>{p.label}</option>)}</select></label>
            <div className="rounded-2xl bg-slate-50 p-3 text-sm"><div className="font-medium">Headers</div><div className="mt-1 text-xs">{headers.length ? headers.slice(0, 5).join(" | ") : "No data"}</div></div>
          </div>
          <div className="mt-4 grid gap-2 md:grid-cols-3">
            {Object.keys(mapping).map(k => <label key={k} className="text-sm"><div className="mb-1 font-medium">{k}</div><select value={mapping[k]} onChange={e => setMapping(c => ({ ...c, [k]: e.target.value }))} className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2"><option value="">Not mapped</option>{headers.map(h => <option key={h} value={h}>{h}</option>)}</select></label>)}
          </div>
          <div className="mt-4 flex flex-wrap gap-2">
            <button onClick={() => setMapping(detectMapping(headers, activePreset))} className="rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm font-medium">Auto-detect</button>
            <button onClick={buildFromSheet} className="rounded-2xl bg-slate-900 px-4 py-2 text-sm font-medium text-white">Generate XML</button>
          </div>
          <div className="mt-4 rounded-2xl border border-slate-200 bg-white p-3">
            <div className="font-medium text-sm">Sheet preview</div>
            <div className="mt-2 max-h-40 overflow-auto space-y-1">{sheetRows.length === 0 ? <div className="text-sm">No rows loaded.</div> : sheetRows.slice(0, 5).map((r, i) => <div key={i} className="rounded-lg bg-slate-50 p-2 text-xs">{headers.slice(0, 4).map(h => `${h}=${r[h]}`).join(" | ")}</div>)}</div>
          </div>
        </Section>
      </div>
      <div className="space-y-6">
        <VisualWorkflowDashboard form={form} title="Template workflow" subtitle="Workflow from spreadsheet." />
        <Section title="XML Output" subtitle="Review and export.">
          <textarea value={templateXml} onChange={e => setTemplateXml(e.target.value)} rows={16} className="w-full rounded-2xl border border-slate-200 bg-slate-950 px-3 py-3 font-mono text-xs leading-5 text-emerald-300" />
          <div className="mt-3 flex gap-2"><button onClick={() => downloadText(`${form.workflowType}-template.xml`, templateXml)} className="rounded-2xl bg-slate-900 px-4 py-2 text-sm font-medium text-white">Export XML</button></div>
          <div className="mt-3">{issues.length === 0 ? <div className="rounded-2xl border border-emerald-200 bg-emerald-50 p-3 text-sm text-emerald-800">No issues.</div> : issues.map(i => <div key={i} className="rounded-2xl border border-amber-200 bg-amber-50 p-3 text-sm text-amber-900 mb-2">{i}</div>)}</div>
        </Section>
      </div>
    </div>
  );
};

const QuestionnaireMode = ({ questionnaire, setQuestionnaire, questionnaireXml, setQuestionnaireXml }) => {
  const formFromQ = useMemo(() => questionnaireToForm(questionnaire), [questionnaire]);
  const blueprint = useMemo(() => {
    const m = buildWorkflowModel(formFromQ);
    return [`Customer: ${questionnaire.customerName || "(not set)"}`, `Type: ${questionnaire.workflowType}`, `Vertical: ${questionnaire.vertical}`, `Dept: ${questionnaire.routeByDepartment ? "Yes" : "No"}`, `Commodity: ${questionnaire.routeByCommodity ? "Yes" : "No"}`, `Amount: ${questionnaire.routeByAmount ? `Yes (${questionnaire.highValueThreshold})` : "No"}`, `GL: ${questionnaire.routeByGl ? "Yes" : "No"}`, "", "Steps", ...m.steps.map((s, i) => `${i + 1}. ${s.name}`)].join("\n");
  }, [questionnaire, formFromQ]);
  const issues = useMemo(() => validateXml(questionnaireXml), [questionnaireXml]);
  const questions = useMemo(() => [...questionBank.foundations, ...questionBank.governance, ...(verticals[questionnaire.vertical]?.questions || []), ...questionBank.technical], [questionnaire.vertical]);

  return (
    <div className="grid gap-6 xl:grid-cols-2">
      <div className="space-y-6">
        <Section title="Questionnaire" subtitle="Capture customer decisions.">
          <div className="grid gap-3 md:grid-cols-2">
            <label className="text-sm"><div className="mb-1 font-medium">Customer name</div><input value={questionnaire.customerName} onChange={e => setQuestionnaire(c => ({ ...c, customerName: e.target.value }))} className="w-full rounded-2xl border border-slate-200 px-3 py-2" /></label>
            <label className="text-sm"><div className="mb-1 font-medium">Workflow type</div><select value={questionnaire.workflowType} onChange={e => setQuestionnaire(c => ({ ...c, workflowType: e.target.value }))} className="w-full rounded-2xl border border-slate-200 bg-white px-3 py-2"><option value="requisition">requisition</option><option value="receipt">receipt</option><option value="contract">contract</option></select></label>
            <label className="text-sm"><div className="mb-1 font-medium">Vertical</div><select value={questionnaire.vertical} onChange={e => setQuestionnaire(c => ({ ...c, vertical: e.target.value }))} className="w-full rounded-2xl border border-slate-200 bg-white px-3 py-2">{Object.keys(verticals).map(v => <option key={v} value={v}>{v}</option>)}</select></label>
            <label className="text-sm"><div className="mb-1 font-medium">High value threshold</div><input value={questionnaire.highValueThreshold} onChange={e => setQuestionnaire(c => ({ ...c, highValueThreshold: e.target.value }))} className="w-full rounded-2xl border border-slate-200 px-3 py-2" /></label>
          </div>
          <div className="mt-4 grid gap-2 md:grid-cols-2">
            <label className="inline-flex items-center gap-2 rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm"><input type="checkbox" checked={questionnaire.routeByDepartment} onChange={e => setQuestionnaire(c => ({ ...c, routeByDepartment: e.target.checked }))} /> Route by department</label>
            <label className="inline-flex items-center gap-2 rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm"><input type="checkbox" checked={questionnaire.routeByCommodity} onChange={e => setQuestionnaire(c => ({ ...c, routeByCommodity: e.target.checked }))} /> Route by commodity</label>
            <label className="inline-flex items-center gap-2 rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm"><input type="checkbox" checked={questionnaire.routeByAmount} onChange={e => setQuestionnaire(c => ({ ...c, routeByAmount: e.target.checked }))} /> Route by amount</label>
            <label className="inline-flex items-center gap-2 rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm"><input type="checkbox" checked={questionnaire.routeByGl} onChange={e => setQuestionnaire(c => ({ ...c, routeByGl: e.target.checked }))} /> Route by GL</label>
            <label className="inline-flex items-center gap-2 rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm"><input type="checkbox" checked={questionnaire.includeExpiry} onChange={e => setQuestionnaire(c => ({ ...c, includeExpiry: e.target.checked }))} /> Include expiry</label>
            <label className="inline-flex items-center gap-2 rounded-2xl border border-slate-200 bg-white px-4 py-2 text-sm"><input type="checkbox" checked={questionnaire.needsInventoryRobot} onChange={e => setQuestionnaire(c => ({ ...c, needsInventoryRobot: e.target.checked }))} /> Inventory automation</label>
          </div>
          <div className="mt-4 grid gap-2 md:grid-cols-3">
            <label className="text-sm"><div className="mb-1 font-medium">Dept folder</div><input value={questionnaire.departmentFolder} onChange={e => setQuestionnaire(c => ({ ...c, departmentFolder: e.target.value }))} className="w-full rounded-xl border border-slate-200 px-3 py-2" /></label>
            <label className="text-sm"><div className="mb-1 font-medium">Commodity folder</div><input value={questionnaire.commodityFolder} onChange={e => setQuestionnaire(c => ({ ...c, commodityFolder: e.target.value }))} className="w-full rounded-xl border border-slate-200 px-3 py-2" /></label>
            <label className="text-sm"><div className="mb-1 font-medium">GL folder</div><input value={questionnaire.glFolder} onChange={e => setQuestionnaire(c => ({ ...c, glFolder: e.target.value }))} className="w-full rounded-xl border border-slate-200 px-3 py-2" /></label>
          </div>
          <textarea value={questionnaire.notes} onChange={e => setQuestionnaire(c => ({ ...c, notes: e.target.value }))} rows={3} className="mt-4 w-full rounded-2xl border border-slate-200 bg-white px-3 py-2 text-sm" placeholder="Notes and exceptions" />
          <div className="mt-4"><button onClick={() => setQuestionnaireXml(buildXmlFromForm(formFromQ))} className="rounded-2xl bg-slate-900 px-4 py-2 text-sm font-medium text-white">Generate XML</button></div>
        </Section>
        <Section title="Questions" subtitle="Workshop prompts.">
          <div className="space-y-2 max-h-[300px] overflow-auto">{questions.map((q, i) => <div key={q} className="rounded-xl border border-slate-200 bg-slate-50 p-2 text-sm"><span className="font-semibold mr-1">Q{i + 1}.</span>{q}</div>)}</div>
        </Section>
      </div>
      <div className="space-y-6">
        <VisualWorkflowDashboard form={formFromQ} title="Questionnaire workflow" subtitle="From customer answers." />
        <Section title="Blueprint" subtitle="Summary."><pre className="max-h-[200px] overflow-auto rounded-2xl bg-slate-950 p-4 text-xs leading-5 text-emerald-300">{blueprint}</pre></Section>
        <Section title="XML Output" subtitle="Review and export.">
          <textarea value={questionnaireXml} onChange={e => setQuestionnaireXml(e.target.value)} rows={14} className="w-full rounded-2xl border border-slate-200 bg-slate-950 px-3 py-3 font-mono text-xs leading-5 text-emerald-300" />
          <div className="mt-3"><button onClick={() => downloadText(`${questionnaire.workflowType}-questionnaire.xml`, questionnaireXml)} className="rounded-2xl bg-slate-900 px-4 py-2 text-sm font-medium text-white">Export XML</button></div>
          <div className="mt-3">{issues.length === 0 ? <div className="rounded-2xl border border-emerald-200 bg-emerald-50 p-3 text-sm text-emerald-800">No issues.</div> : issues.map(i => <div key={i} className="rounded-2xl border border-amber-200 bg-amber-50 p-3 text-sm text-amber-900 mb-2">{i}</div>)}</div>
        </Section>
      </div>
    </div>
  );
};

// Main App
const App = () => {
  const [mode, setMode] = useState("builder");
  const [builderForm, setBuilderForm] = useState(BUILDER_DEFAULTS);
  const [builderXml, setBuilderXml] = useState(buildXmlFromForm(BUILDER_DEFAULTS));
  const [templateForm, setTemplateForm] = useState(BUILDER_DEFAULTS);
  const [templateXml, setTemplateXml] = useState(buildXmlFromForm(BUILDER_DEFAULTS));
  const [questionnaire, setQuestionnaire] = useState(QUESTIONNAIRE_DEFAULTS);
  const [questionnaireXml, setQuestionnaireXml] = useState(buildXmlFromForm(questionnaireToForm(QUESTIONNAIRE_DEFAULTS)));

  const rec = mode === "builder" ? "Mode 1: Build workflow directly in the app." : mode === "template" ? "Mode 2: Import customer spreadsheet." : "Mode 3: Use questionnaire answers.";

  return (
    <div className="min-h-screen bg-slate-100 text-slate-900">
      <div className="mx-auto max-w-7xl p-4 md:p-6">
        <div className="mb-6 rounded-[28px] bg-slate-900 p-6 text-white shadow-xl">
          <div className="grid gap-6 lg:grid-cols-[1.5fr,1fr]">
            <div>
              <div className="mb-2 text-sm text-slate-300">Jaggaer Approval Workflow Studio V7</div>
              <h1 className="text-2xl md:text-3xl font-semibold tracking-tight">Three workflow-generation options in one app.</h1>
              <p className="mt-3 max-w-2xl text-sm leading-6 text-slate-300">Build workflows directly, import from spreadsheets, or use questionnaires. Each mode generates and exports XML independently.</p>
              <div className="mt-4 flex flex-wrap gap-2">
                <SmallTag>Builder</SmallTag><SmallTag>Template Import</SmallTag><SmallTag>Questionnaire</SmallTag><SmallTag>XML Export</SmallTag>
              </div>
            </div>
            <div className="rounded-3xl border border-white/10 bg-white/5 p-4">
              <div className="text-sm text-slate-300">Current focus</div>
              <div className="mt-2 text-lg font-semibold">{rec}</div>
              <div className="mt-4 grid grid-cols-3 gap-2">
                <button onClick={() => setMode("builder")} className={mode === "builder" ? "rounded-2xl bg-white px-3 py-2 text-sm font-medium text-slate-900" : "rounded-2xl bg-white/10 px-3 py-2 text-sm font-medium text-white"}>Builder</button>
                <button onClick={() => setMode("template")} className={mode === "template" ? "rounded-2xl bg-white px-3 py-2 text-sm font-medium text-slate-900" : "rounded-2xl bg-white/10 px-3 py-2 text-sm font-medium text-white"}>Template</button>
                <button onClick={() => setMode("questionnaire")} className={mode === "questionnaire" ? "rounded-2xl bg-white px-3 py-2 text-sm font-medium text-slate-900" : "rounded-2xl bg-white/10 px-3 py-2 text-sm font-medium text-white"}>Questions</button>
              </div>
            </div>
          </div>
        </div>
        {mode === "builder" && <BuilderMode form={builderForm} setForm={setBuilderForm} xmlDraft={builderXml} setXmlDraft={setBuilderXml} />}
        {mode === "template" && <TemplateMode form={templateForm} setForm={setTemplateForm} templateXml={templateXml} setTemplateXml={setTemplateXml} />}
        {mode === "questionnaire" && <QuestionnaireMode questionnaire={questionnaire} setQuestionnaire={setQuestionnaire} questionnaireXml={questionnaireXml} setQuestionnaireXml={setQuestionnaireXml} />}
      </div>
    </div>
  );
};

ReactDOM.createRoot(document.getElementById("root")).render(<App />);
